const totalTextures = 3;

function onTextureLoad() {
  texturesLoaded++;
  if (texturesLoaded >= totalTextures) {
    loadGeoData();
  }
}

function onTextureError() { onTextureLoad(); } // Continue loading even if a texture fails
const earthColor = textureLoader.load(earthColorUrl, onTextureLoad, undefined, onTextureError);
const earthBump = textureLoader.load(earthBumpUrl, onTextureLoad, undefined, onTextureError);
const earthSpec = textureLoader.load(earthSpecUrl, onTextureLoad, undefined, onTextureError);

const earthGeometry = new THREE.SphereGeometry(GLOBE_RADIUS, 128, 64);
const earthMaterial = new THREE.MeshPhongMaterial({
  map: earthColor,
  bumpMap: earthBump,
  bumpScale: 0.015,
  specularMap: earthSpec,
  specular: new THREE.Color(0x222244),
  shininess: 15,
});

const earthMesh = new THREE.Mesh(earthGeometry, earthMaterial);
globeGroup.add(earthMesh);

// Atmosphere
const atmosphereMaterial = new THREE.ShaderMaterial({
  vertexShader: `
    varying vec3 vNormal;
    varying vec3 vPosition;
    void main() {
      vNormal = normalize(normalMatrix * normal);
      vPosition = (modelViewMatrix * vec4(position, 1.0)).xyz;
      gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
    }
  `,
  fragmentShader: `
    varying vec3 vNormal;
    varying vec3 vPosition;
    void main() {
      vec3 viewDir = normalize(-vPosition);
      float fresnel = 1.0 - dot(viewDir, vNormal);
      fresnel = pow(fresnel, 3.5);
      vec3 color = mix(vec3(0.15, 0.4, 0.9), vec3(0.35, 0.65, 1.0), fresnel);
      gl_FragColor = vec4(color, fresnel * 0.3);
    }
  `,
  transparent: true,
  side: THREE.FrontSide,
  depthWrite: false,
});
globeGroup.add(new THREE.Mesh(
  new THREE.SphereGeometry(GLOBE_RADIUS * 1.012, 64, 32),
  atmosphereMaterial
));

