function latLngToVec3(lat, lng, r) {
  const phi = (90 - lat) * (Math.PI / 180);
  const theta = (lng + 180) * (Math.PI / 180);
  return new THREE.Vector3(
    -r * Math.sin(phi) * Math.cos(theta),
    r * Math.cos(phi),
    r * Math.sin(phi) * Math.sin(theta)
  );
}

function createBorderLine(coords, radius, color) {
  const points = coords.map(c => latLngToVec3(c[1], c[0], radius));
  const geo = new THREE.BufferGeometry().setFromPoints(points);
  return new THREE.Line(geo, new THREE.LineBasicMaterial({
    color, transparent: true, opacity: 0.35,
  }));
}

function createPickMesh(coords, name, radius) {
  const points = coords.map(c => latLngToVec3(c[1], c[0], radius + 0.003));
  if (points.length < 3) return null;

  const center = new THREE.Vector3();
  points.forEach(p => center.add(p));
  center.divideScalar(points.length);

  const verts = [];
  for (let i = 0; i < points.length - 1; i++) {
    verts.push(center.x, center.y, center.z);
    verts.push(points[i].x, points[i].y, points[i].z);
    verts.push(points[i + 1].x, points[i + 1].y, points[i + 1].z);
  }

  const geo = new THREE.BufferGeometry();
  geo.setAttribute('position', new THREE.Float32BufferAttribute(verts, 3));
  geo.computeVertexNormals();

  const mesh = new THREE.Mesh(geo, new THREE.MeshBasicMaterial({
    color: 0xffffff, transparent: true, opacity: 0, side: THREE.DoubleSide, depthWrite: false,
  }));
  mesh.userData.countryName = name;
  return mesh;
}

async function loadGeoData() {
  try {
    const res = await fetch('https://cdn.jsdelivr.net/npm/world-atlas@2/countries-110m.json');
    const topo = await res.json();
    const features = topojson.feature(topo, topo.objects.countries).features;

    for (const feature of features) {
      const name = COUNTRY_ID_MAP[feature.id] || null;
      if (!name) continue;

      const isFeatured = name in COUNTRIES;
      const borderColor = isFeatured ? 0x8a9aaa : 0x1e3f55;

      const processRing = (ring) => {
        const line = createBorderLine(ring, GLOBE_RADIUS + 0.001, borderColor);
        line.userData.countryName = name;
        countriesGroup.add(line);

        if (!countryBorders[name]) countryBorders[name] = [];
        countryBorders[name].push(line);

        if (isFeatured) {
          const mesh = createPickMesh(ring, name, GLOBE_RADIUS);
          if (mesh) {
            countriesGroup.add(mesh);
            countryMeshes.push(mesh);
          }
        }
      };

      const geom = feature.geometry;
      if (geom.type === 'Polygon') {
        geom.coordinates.forEach(processRing);
      } else if (geom.type === 'MultiPolygon') {
        geom.coordinates.forEach(poly => poly.forEach(processRing));
      }
    }

    // Fade out loading
    loadingOverlay.classList.add('fade-out');
    setTimeout(() => loadingOverlay.remove(), 800);
  } catch (err) {
    console.error('Failed to load geo data:', err);
    loadingOverlay.querySelector('.loading-text').textContent = 'Failed to load — please refresh';
  }
}

