const bookingModal = document.getElementById('booking-modal');
const bookingForm = document.getElementById('booking-form');
const bookingSuccess = document.getElementById('booking-success');
const bookingModalClose = document.getElementById('booking-modal-close');
const bookingModalTag = document.getElementById('booking-modal-tag');
const bookingModalTitle = document.getElementById('booking-modal-title');
const bookingModalSubtitle = document.getElementById('booking-modal-subtitle');

let currentBookingContext = {};

function openBookingModal(countryName, offerTitle, offerType, offerPrice) {
  currentBookingContext = { countryName, offerTitle, offerType, offerPrice };
  bookingModalTag.textContent = `${offerType} · ${countryName}`;
  bookingModalTitle.textContent = offerTitle;
  bookingModalSubtitle.textContent = `From ${offerPrice} — reserve your spot with no commitment.`;
  bookingForm.style.display = '';
  bookingSuccess.classList.remove('show');
  bookingForm.reset();
  bookingModal.classList.add('open');
  bookingModal.setAttribute('aria-hidden', 'false');
}

function closeBookingModal() {
  bookingModal.classList.remove('open');
  bookingModal.setAttribute('aria-hidden', 'true');
}

bookingModalClose.addEventListener('click', closeBookingModal);
bookingModal.querySelector('.booking-modal-backdrop').addEventListener('click', closeBookingModal);
document.addEventListener('keydown', e => { if (e.key === 'Escape' && bookingModal.classList.contains('open')) closeBookingModal(); });

bookingForm.addEventListener('submit', (e) => {
  e.preventDefault();
  const formData = new FormData(bookingForm);
  const data = Object.fromEntries(formData.entries());
  data.country = currentBookingContext.countryName;
  data.offer = currentBookingContext.offerTitle;
  data.offerType = currentBookingContext.offerType;
  console.log('Booking request:', data);
  bookingForm.style.display = 'none';
  bookingSuccess.classList.add('show');
  setTimeout(closeBookingModal, 3000);
});

// ─── Interaction ────────────────────────────────────────────────────────────

const raycaster = new THREE.Raycaster();
const mouse = new THREE.Vector2();
const mousePos = { x: 0, y: 0 };

function onPointerMove(e) {
  mouse.x = (e.clientX / window.innerWidth) * 2 - 1;
  mouse.y = -(e.clientY / window.innerHeight) * 2 + 1;
  mousePos.x = e.clientX;
  mousePos.y = e.clientY;
}

function highlightCountry(name) {
  if (hoveredCountry === name) return;
  if (hoveredCountry) clearHighlight(hoveredCountry);
  hoveredCountry = name;

  if (!countryBorders[name]) return;

  for (const line of countryBorders[name]) {
    line.material.color.setHex(0xdde0e4);
    line.material.opacity = 0.9;
    line.scale.setScalar(1.008);
  }
  for (const mesh of countryMeshes) {
    if (mesh.userData.countryName === name) mesh.material.opacity = 0.1;
  }

  const data = COUNTRIES[name];
  if (data) {
    tooltip.innerHTML = `${name}<span class="tooltip-region">${data.region}</span>`;
    tooltip.classList.add('visible');
    document.body.style.cursor = 'pointer';
  }
}

function clearHighlight(name) {
  if (!countryBorders[name]) return;
  const isFeatured = name in COUNTRIES;

  for (const line of countryBorders[name]) {
    line.material.color.setHex(isFeatured ? 0x8a9aaa : 0x1e3f55);
    line.material.opacity = 0.35;
    line.scale.setScalar(1);
  }
  for (const mesh of countryMeshes) {
    if (mesh.userData.countryName === name) mesh.material.opacity = 0;
  }
  tooltip.classList.remove('visible');
  document.body.style.cursor = 'grab';
}

function onPointerDown(e) {
  onPointerDown._startX = e.clientX;
  onPointerDown._startY = e.clientY;
}

function onPointerUp(e) {
  const dx = Math.abs(e.clientX - (onPointerDown._startX || 0));
  const dy = Math.abs(e.clientY - (onPointerDown._startY || 0));
  if (dx > 5 || dy > 5) return;
  if (hoveredCountry && hoveredCountry in COUNTRIES) {
    openPanel(hoveredCountry);
  }
}

function dimGlobe(dim) {
  container.classList.toggle('dimmed', dim);
}

function staggerPanelContent() {
  const els = panel.querySelectorAll('.panel-hero, .panel-desc, .panel-social-proof, .offer-card, .panel-sticky-cta');
  els.forEach((el, i) => {
    el.classList.add('panel-stagger');
    el.classList.remove('visible');
    setTimeout(() => el.classList.add('visible'), 80 * (i + 1));
  });
}

function openPanel(name) {
  const data = COUNTRIES[name];
  if (!data) return;

  // Close any open page panels and book panel
  Object.values(pageOverlays).forEach(p => p.classList.remove('open'));
  bookPanel.classList.remove('open');

  panelRegion.textContent = data.region;
  panelCountryName.textContent = name;
  panelCountryDesc.textContent = data.desc;

  // Hero image
  const existingImg = panelHero.querySelector('img');
  if (existingImg) existingImg.remove();

  const imagePath = IMAGE_MAP[name];
  if (imagePath) {
    const img = document.createElement('img');
    img.src = imagePath;
    img.alt = name;
    img.loading = 'eager';
    img.onerror = () => { panelHero.style.display = 'none'; };
    panelHero.insertBefore(img, panelHero.firstChild);
    panelHero.style.display = '';
  } else {
    panelHero.style.display = 'none';
  }

  // Social proof
  const { rating, reviews } = getCountryRating(name);
  const fullStars = Math.floor(rating);
  const hasHalf = rating % 1 >= 0.4;
  let starsHtml = '';
  for (let i = 0; i < 5; i++) {
    if (i < fullStars) starsHtml += '<span class="panel-star">&#9733;</span>';
    else if (i === fullStars && hasHalf) starsHtml += '<span class="panel-star">&#9733;</span>';
    else starsHtml += '<span class="panel-star empty">&#9733;</span>';
  }

  panel.querySelectorAll('.panel-social-proof, .panel-sticky-cta').forEach(el => el.remove());

  const socialProof = document.createElement('div');
  socialProof.className = 'panel-social-proof';
  socialProof.innerHTML = `
    <div class="panel-stars">${starsHtml}</div>
    <span class="panel-rating-text">${rating}</span>
    <span class="panel-review-count">${reviews.toLocaleString()} traveler reviews</span>
  `;
  panelCountryDesc.parentNode.insertBefore(socialProof, panelCountryDesc.nextSibling);

  // Offer cards
  panelOffers.innerHTML = data.offers.map((offer, i) => {
    const badge = getScarcityBadge(i, name);
    const originalPrice = getOriginalPrice(offer.price);
    const badgeHtml = badge ? `<span class="offer-card-badge">${badge}</span>` : '';
    const origHtml = originalPrice ? `<span class="offer-card-original-price">${originalPrice}</span>` : '';

    return `
      <article class="offer-card">
        <div class="offer-card-header">
          <span class="offer-card-type">${offer.type}</span>
          ${badgeHtml}
          <div class="offer-card-price-wrap">
            ${origHtml}
            <span class="offer-card-price">${offer.price} <span>/ ${offer.per}</span></span>
          </div>
        </div>
        <h3>${offer.title}</h3>
        <p class="offer-card-desc">${offer.desc}</p>
        <div class="offer-card-details">
          ${offer.details.map(d => `<span class="offer-detail">${d}</span>`).join('')}
        </div>
        <button class="offer-card-book" data-country="${name}" data-title="${offer.title}" data-type="${offer.type}" data-price="${offer.price}">Book now</button>
      </article>
    `;
  }).join('');

  panelOffers.querySelectorAll('.offer-card-book').forEach(btn => {
    btn.addEventListener('click', () => {
      openBookingModal(btn.dataset.country, btn.dataset.title, btn.dataset.type, btn.dataset.price);
    });
  });

  // Sticky CTA
  const stickyCta = document.createElement('div');
  stickyCta.className = 'panel-sticky-cta';
  stickyCta.innerHTML = `<button class="panel-sticky-btn">Book your ${name} trip</button>`;
  panel.querySelector('.panel-body').appendChild(stickyCta);
  stickyCta.querySelector('.panel-sticky-btn').addEventListener('click', () => {
    const firstOffer = data.offers[0];
    openBookingModal(name, firstOffer.title, firstOffer.type, firstOffer.price);
  });

  panel.classList.add('open');
  dimGlobe(true);
  controls.autoRotate = false;

  // Stagger content after panel slides in
  setTimeout(staggerPanelContent, 80);
}

function closePanel() {
  panel.classList.remove('open');
  const anyPageOpen = Object.values(pageOverlays).some(p => p.classList.contains('open'));
  const bookOpen = bookPanel.classList.contains('open');
  if (!anyPageOpen && !bookOpen) {
    dimGlobe(false);
    setTimeout(() => { controls.autoRotate = true; }, 300);
  }
}

panelClose.addEventListener('click', closePanel);
document.addEventListener('keydown', e => { if (e.key === 'Escape') closePanel(); });

window.addEventListener('pointermove', onPointerMove);
window.addEventListener('pointerdown', onPointerDown);
window.addEventListener('pointerup', onPointerUp);

// ─── Search & Fly-To ─────────────────────────────────────────────────────

const searchInput = document.getElementById('search-input');
const searchResults = document.getElementById('search-results');
const searchKbd = document.getElementById('search-kbd');

const countryNames = Object.keys(COUNTRIES);
let searchActiveIndex = -1;

// Keyboard shortcut: "/" to focus search
document.addEventListener('keydown', (e) => {
  if (e.key === '/' && document.activeElement !== searchInput &&
      !bookingModal.classList.contains('open')) {
    e.preventDefault();
    searchInput.focus();
  }
});

searchInput.addEventListener('focus', () => {
  searchKbd.style.display = 'none';
  controls.autoRotate = false;
});

searchInput.addEventListener('blur', () => {
  searchKbd.style.display = '';
  setTimeout(() => {
    searchResults.classList.remove('open');
    searchActiveIndex = -1;
    if (!panel.classList.contains('open')) controls.autoRotate = true;
  }, 200);
});

searchInput.addEventListener('input', () => {
  const q = searchInput.value.trim().toLowerCase();
  searchActiveIndex = -1;

  if (!q) {
    searchResults.classList.remove('open');
    searchResults.innerHTML = '';
    return;
  }

  const matches = countryNames.filter(n => n.toLowerCase().includes(q)).slice(0, 6);

  if (matches.length === 0) {
    searchResults.innerHTML = '<li class="search-no-results">No destinations found</li>';
    searchResults.classList.add('open');
    return;
  }

  searchResults.innerHTML = matches.map((name, i) => {
    const data = COUNTRIES[name];
    const idx = name.toLowerCase().indexOf(q);
    const highlighted = name.slice(0, idx) + '<mark>' + name.slice(idx, idx + q.length) + '</mark>' + name.slice(idx + q.length);
    return `<li class="search-result-item" role="option" data-name="${name}" data-index="${i}">
      <span class="search-result-name">${highlighted}</span>
      <span class="search-result-region">${data.region}</span>
    </li>`;
  }).join('');

  searchResults.classList.add('open');
});

// Event delegation for search results (avoids re-attaching listeners on each input)
searchResults.addEventListener('mousedown', (e) => {
  const item = e.target.closest('.search-result-item');
  if (!item) return;
  e.preventDefault();
  selectSearchResult(item.dataset.name);
});

searchInput.addEventListener('keydown', (e) => {
  const items = searchResults.querySelectorAll('.search-result-item');
  if (!items.length) return;

  if (e.key === 'ArrowDown') {
    e.preventDefault();
    searchActiveIndex = Math.min(searchActiveIndex + 1, items.length - 1);
    updateActiveResult(items);
  } else if (e.key === 'ArrowUp') {
    e.preventDefault();
    searchActiveIndex = Math.max(searchActiveIndex - 1, 0);
    updateActiveResult(items);
  } else if (e.key === 'Enter' && searchActiveIndex >= 0) {
    e.preventDefault();
    selectSearchResult(items[searchActiveIndex].dataset.name);
  } else if (e.key === 'Escape') {
    searchInput.blur();
  }
});

function updateActiveResult(items) {
  items.forEach((item, i) => {
    item.classList.toggle('active', i === searchActiveIndex);
  });
}

function selectSearchResult(name) {
  searchInput.value = '';
  searchResults.classList.remove('open');
  searchResults.innerHTML = '';
  searchInput.blur();

  flyToCountry(name);
}

// ─── Fly-To Animation ────────────────────────────────────────────────────

let flyAnimation = null;

function flyToCountry(name) {
  const coords = COUNTRY_COORDS[name];
  if (!coords) return;

  const [lng, lat] = coords;

  // We need to position the camera so the target country faces the camera.
  // The globe rotates via globeGroup — we animate the camera around the globe instead.
  const targetCamPos = latLngToVec3(lat, lng, 2.4); // distance from center

  const startPos = camera.position.clone();
  const startTarget = controls.target.clone();
  const endTarget = new THREE.Vector3(0, 0, 0);

  // Cancel previous animation
  if (flyAnimation) cancelAnimationFrame(flyAnimation);
  controls.autoRotate = false;

  const duration = 1200; // ms
  const startTime = performance.now();

  // Highlight the country immediately
  highlightCountry(name);

  function animateFly(now) {
    const elapsed = now - startTime;
    let t = Math.min(elapsed / duration, 1);
    // Ease-out cubic
    t = 1 - Math.pow(1 - t, 3);

    camera.position.lerpVectors(startPos, targetCamPos, t);
    controls.target.lerpVectors(startTarget, endTarget, t);
    controls.update();

    if (t < 1) {
      flyAnimation = requestAnimationFrame(animateFly);
    } else {
      flyAnimation = null;
      // Open the panel after arrival
      if (name in COUNTRIES) {
        openPanel(name);
      }
    }
  }

  flyAnimation = requestAnimationFrame(animateFly);
}

// ─── Render Loop ────────────────────────────────────────────────────────────

function animate() {
  requestAnimationFrame(animate);
  controls.update();

  raycaster.setFromCamera(mouse, camera);
  const hits = raycaster.intersectObjects(countryMeshes);

  if (hits.length > 0) {
    const name = hits[0].object.userData.countryName;
    if (name in COUNTRIES) {
      highlightCountry(name);
      tooltip.style.transform = `translate(${mousePos.x + 14}px, ${mousePos.y - 14}px)`;
    }
  } else if (hoveredCountry) {
    clearHighlight(hoveredCountry);
    hoveredCountry = null;
  }

  renderer.render(scene, camera);
}

animate();

