// ─── Destinations Page ────────────────────────────────────────────────────

const destGrid = document.getElementById('dest-grid');
const destFilters = document.getElementById('dest-filters');

// Featured countries get double-width cards
const FEATURED_DESTINATIONS = new Set([
  'Japan', 'Italy', 'Iceland', 'Morocco', 'Maldives', 'Australia', 'Peru'
]);

// Display name overrides
const DISPLAY_NAMES = {
  'United States of America': 'United States',
  'United Arab Emirates': 'UAE',
  'Czech Republic': 'Czechia',
};

function getLowestPrice(country) {
  const data = COUNTRIES[country];
  if (!data || !data.offers || !data.offers.length) return null;
  let lowest = Infinity;
  for (const offer of data.offers) {
    const num = parseInt(offer.price.replace(/[^0-9]/g, ''));
    if (!isNaN(num) && num < lowest) lowest = num;
  }
  return lowest === Infinity ? null : lowest;
}

function renderDestGrid(regionFilter) {
  const entries = Object.entries(COUNTRIES)
    .filter(([, data]) => regionFilter === 'all' || data.region === regionFilter);

  // Sort: featured first, then alphabetical
  entries.sort((a, b) => {
    const aFeat = FEATURED_DESTINATIONS.has(a[0]) ? 0 : 1;
    const bFeat = FEATURED_DESTINATIONS.has(b[0]) ? 0 : 1;
    if (aFeat !== bFeat) return aFeat - bFeat;
    return a[0].localeCompare(b[0]);
  });

  destGrid.innerHTML = entries.map(([name, data], i) => {
    const isFeatured = FEATURED_DESTINATIONS.has(name);
    const displayName = DISPLAY_NAMES[name] || name;
    const imgPath = IMAGE_MAP[name] || '';
    const lowestPrice = getLowestPrice(name);
    const priceLabel = lowestPrice ? `From $${lowestPrice.toLocaleString()}` : '';
    const delay = Math.min(i * 0.04, 0.8);

    return `
      <article class="dest-card${isFeatured ? ' featured' : ''}" data-country="${name}" style="animation-delay:${delay}s">
        <div class="dest-card-img" style="background-image:url('${imgPath}')"></div>
        <div class="dest-card-overlay"></div>
        <div class="dest-card-body">
          <span class="dest-card-region">${data.region}</span>
          <h2 class="dest-card-name">${displayName}</h2>
          <span class="dest-card-price">${priceLabel}</span>
          <p class="dest-card-desc">${data.desc}</p>
        </div>
      </article>
    `;
  }).join('');

  // Click handlers — fly to country on globe
  destGrid.querySelectorAll('.dest-card').forEach(card => {
    card.addEventListener('click', () => {
      const name = card.dataset.country;
      closeAllPages();
      flyToCountry(name);
    });
  });
}

// Filter buttons
if (destFilters) {
  destFilters.addEventListener('click', (e) => {
    const btn = e.target.closest('.dest-filter');
    if (!btn) return;
    destFilters.querySelectorAll('.dest-filter').forEach(b => b.classList.remove('active'));
    btn.classList.add('active');
    renderDestGrid(btn.dataset.region);
  });
}

// Render grid when Destinations page opens
const destOverlay = document.getElementById('page-destinations');
const destPageObserver = new MutationObserver(() => {
  if (destOverlay.classList.contains('open')) {
    // Reset filter to "All"
    destFilters.querySelectorAll('.dest-filter').forEach(b => b.classList.remove('active'));
    destFilters.querySelector('[data-region="all"]').classList.add('active');
    renderDestGrid('all');
  }
});
destPageObserver.observe(destOverlay, { attributes: true, attributeFilter: ['class'] });

